#!/bin/sh -e
# Generated by patch2vi from unified diff
# Available separators: 0001-0010 0013-0014 0016-0037 0102-0104 0110 0112-0113 0115 0117-0121 0123 0126 0130-0132 0176-0377

# Pass any argument to use patch(1) instead of nextvi ex commands
if [ -n "$1" ]; then
    sed '1,/^=== PATCH2VI PATCH ===$/d' "$0" | patch -p1 --merge=diff3
    exit $?
fi

VI=${VI:-vi}
if ! $VI -? 2>&1 | grep -q 'Nextvi'; then
    echo "Error: $VI is not nextvi" >&2
    echo "Set VI environment variable to point to nextvi binary" >&2
    exit 1
fi

SEP="$(printf '\001')"
# Command that handles readability line breaks
LB="0?"
# Phase 1 (search/mark): errors disabled by default,
# DBG1=1 enables error reporting, QF1=1 quits on failure
[ "$DBG1" = "1" ] && DBG1= || DBG1="0\?"
[ "$QF1" = "1" ] && QF1="\\${SEP}vis 2\\${SEP}q!1" || QF1=
# Phase 2 (edits): DBG2=1 disables errors, QF2=1 ignores them
[ "$DBG2" = "1" ] && DBG2="0\?" || DBG2=
[ "$QF2" = "1" ] && QF2= || QF2="\\${SEP}vis 2\\${SEP}q!1"
# Enters vi at failing code line in this script
# Designed for state inspection mid execution
[ "$INTR" = "1" ] && INTR="\\${SEP}|sc|\\${SEP}vis 2:0reg:e $0:83reg %@/:%f> %@p:&Q:b0:|sc! \\\\\\${SEP}|:vis 3\\${SEP}q1" || INTR=

# Patch: ex.c
EXINIT="|sc! \\\\${SEP}|:vis 3${SEP}98reg${SEP}b0${SEP}%ya b${SEP}%;f> 			fd < 0 \\\\|\\\\| rd \\\\? 'f' : 'r'\\\\);
	if \\\\(!\\\\(xvis & 4\\\\)\\\\)
		ex_print\\\\(msg, bar_ft\\\\)${SEP}??!${DBG1:-ya!p\\${SEP}prp\\${SEP}p FAIL ex.c:383\\${SEP}pr${INTR}${QF1}}${SEP}${LB}
${SEP}+2m 0${SEP}${LB}
${SEP}'0a 	if (!rd && fd >= 0 && lbuf_len(xb) > 0) {
		int adv = 0;
		while (lbuf_len(xb) > adv+1 && xb->ln[adv][0] == '\\\\n')
			adv++;
		struct filetype lfts[] = {
			{FT(sh), \"^#!.*/(env[ \\\\t]*)?(sh|bash|zsh|dash)([ \\\\t]*.*)?\$\"},
			{FT(py), \"^#!.*/(env[ \\\\t]*)?python3?([ \\\\t]*.*)?\$\"}
		};
		char *pats[LEN(lfts)];
		for (int i = 0; i < LEN(lfts); i++)
			pats[i] = lfts[i].pat;
		rset *rs = rset_make(LEN(lfts), pats, 0);
		int hl = rset_find(rs, xb->ln[adv], NULL, REG_NEWLINE);
		if (hl >= 0)
			xb_ft = syn_setft(lfts[hl].ft);
		rset_free(rs);
	}
${SEP}??!${DBG2:-ya!p\\${SEP}prp\\${SEP}p FAIL ex.c:383:m0\\${SEP}pr${INTR}${QF2}}${SEP}vis 2${SEP}b0${SEP}w${SEP}q" $VI -e 'ex.c'

exit 0
